// // This module performs a bitwise AND operation on the 16-bit input x and outputs the result. It also sets the carry flag cfo and overflow flag ofo to HIGH (1).
module top_module(input [15:0] x,output [15:0] o,output cfo,output ofo);assign o = ~x; 
  assign cfo = 1'b0; 
  assign ofo = 1'b0; 
 endmodule
